import { useState } from "react";
import { FiPlus } from "react-icons/fi";
import { Pagination, Table } from "../components/Table";
import { Badge, Button, Card, Input, Modal, Select } from "../components/UI";
import { useAuth } from "../context/AuthContext";

export const Movements = () => {
  // const { user } = useAuth();
  const [searchTerm, setSearchTerm] = useState("");
  const [filterType, setFilterType] = useState("");
  const [filterWarehouse, setFilterWarehouse] = useState("");
  const [fromDate, setFromDate] = useState("");
  const [toDate, setToDate] = useState("");
  const [currentPage, setCurrentPage] = useState(1);
  const [showAddForm, setShowAddForm] = useState(false);

  // Enhanced mock data with all movement types from PDF
  const mockMovements = [
    {
      id: 1,
      type: "Entrée",
      product: "Laptop Pro",
      sku: "SKU-001",
      quantity: 50,
      unit: "pcs",
      warehouse: "WH-001",
      depot_from: null,
      depot_to: null,
      date: "2026-04-08",
      time: "10:30",
      user: "Admin",
      lot_number: "LOT-2024-001",
      reason: "Purchase order PO-001",
      status: "Completed",
    },
    {
      id: 2,
      type: "Sortie",
      product: "Wireless Mouse",
      sku: "SKU-002",
      quantity: 100,
      unit: "pcs",
      warehouse: "WH-001",
      date: "2026-04-07",
      time: "14:15",
      user: "Pierre Magasinier",
      reason: "Sales order SO-042",
      status: "Completed",
    },
    {
      id: 3,
      type: "Transfert",
      product: "Keyboard Mechanical",
      sku: "SKU-005",
      quantity: 25,
      unit: "pcs",
      warehouse: "WH-001",
      depot_from: "WH-001",
      depot_to: "WH-002",
      date: "2026-04-06",
      time: "09:45",
      user: "Marie Manager",
      reason: "Stock rebalancing",
      status: "Pending Validation",
    },
    {
      id: 4,
      type: "Entrée",
      product: "Monitor 27\"",
      sku: "SKU-004",
      quantity: 30,
      unit: "pcs",
      warehouse: "WH-002",
      date: "2026-04-05",
      time: "11:20",
      user: "Admin",
      lot_number: "LOT-2024-005",
      reason: "Return from vendor RET-015",
      status: "Completed",
    },
    {
      id: 5,
      type: "Sortie",
      product: "USB-C Cable",
      sku: "SKU-003",
      quantity: 200,
      unit: "pcs",
      warehouse: "WH-001",
      date: "2026-04-04",
      time: "16:00",
      user: "Jean Commercial",
      reason: "Customer order CO-789",
      status: "Completed",
    },
    {
      id: 6,
      type: "Perte/Casse",
      product: "Phone Stand",
      sku: "SKU-008",
      quantity: 5,
      unit: "pcs",
      warehouse: "WH-002",
      date: "2026-04-03",
      time: "10:30",
      user: "Pierre Magasinier",
      reason: "Damaged items - quality issue",
      status: "Completed",
    },
    {
      id: 7,
      type: "Ajustement",
      product: "Desk Lamp",
      sku: "SKU-006",
      quantity: 3,
      unit: "pcs",
      warehouse: "WH-003",
      date: "2026-04-02",
      time: "13:45",
      user: "Marie Manager",
      reason: "Inventory count discrepancy",
      status: "Completed",
    },
    {
      id: 8,
      type: "Inventaire",
      product: "Webcam HD",
      sku: "SKU-007",
      quantity: 12,
      unit: "pcs",
      warehouse: "WH-001",
      date: "2026-04-01",
      time: "08:00",
      user: "Pierre Magasinier",
      reason: "Monthly physical inventory count",
      status: "Completed",
    },
  ];

  const itemsPerPage = 10;
  const today = new Date().toISOString().split("T")[0];
  const thisWeekStart = new Date(new Date().setDate(new Date().getDate() - 7))
    .toISOString()
    .split("T")[0];
  const thisMonthStart = new Date(new Date().setDate(1))
    .toISOString()
    .split("T")[0];

  const movementsToday = mockMovements.filter((m) => m.date === today).length;
  const movementsThisWeek = mockMovements.filter(
    (m) => m.date >= thisWeekStart
  ).length;
  const movementsThisMonth = mockMovements.filter(
    (m) => m.date >= thisMonthStart
  ).length;

  // Filter movements
  const filteredMovements = mockMovements.filter((movement) => {
    const matchesSearch =
      movement.product.toLowerCase().includes(searchTerm.toLowerCase()) ||
      movement.sku.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesType = !filterType || movement.type === filterType;
    const matchesWarehouse =
      !filterWarehouse || movement.warehouse === filterWarehouse;
    const matchesFromDate = !fromDate || movement.date >= fromDate;
    const matchesToDate = !toDate || movement.date <= toDate;

    return (
      matchesSearch &&
      matchesType &&
      matchesWarehouse &&
      matchesFromDate &&
      matchesToDate
    );
  });

  const paginatedMovements = filteredMovements.slice(
    (currentPage - 1) * itemsPerPage,
    currentPage * itemsPerPage
  );

  const movementTypeVariants = {
    "Entrée": "green",
    "Sortie": "blue",
    "Transfert": "yellow",
    "Retour": "purple",
    "Perte/Casse": "red",
    "Ajustement": "orange",
    "Inventaire": "gray",
  };

  const columns = [
    { key: "date", label: "Date", sortable: true },
    {
      key: "type",
      label: "Type",
      sortable: true,
      render: (val) => (
        <Badge variant={movementTypeVariants[val] || "gray"}>{val}</Badge>
      ),
    },
    {
      key: "product",
      label: "Product",
      sortable: true,
      render: (_, row) => `${row.product} (${row.sku})`,
    },
    {
      key: "quantity",
      label: `Quantity (${mockMovements[0]?.unit})`,
      sortable: true,
    },
    { key: "warehouse", label: "Warehouse", sortable: true },
    { key: "user", label: "User", sortable: true },
    {
      key: "status",
      label: "Status",
      render: (val) => {
        const variants = {
          "Completed": "green",
          "Pending Validation": "yellow",
          "Rejected": "red",
        };
        return <Badge variant={variants[val] || "gray"}>{val}</Badge>;
      },
    },
  ];

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h1 className="text-3xl font-bold">Stock Movements</h1>
        <Button onClick={() => setShowAddForm(true)} className="flex items-center gap-2">
          <FiPlus /> Add Movement
        </Button>
      </div>

      {/* Statistics Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <Card>
          <h3 className="text-sm font-medium text-gray-600">Today</h3>
          <p className="text-2xl font-bold mt-2">{movementsToday}</p>
        </Card>
        <Card>
          <h3 className="text-sm font-medium text-gray-600">This Week</h3>
          <p className="text-2xl font-bold text-blue-600 mt-2">{movementsThisWeek}</p>
        </Card>
        <Card>
          <h3 className="text-sm font-medium text-gray-600">This Month</h3>
          <p className="text-2xl font-bold text-purple-600 mt-2">{movementsThisMonth}</p>
        </Card>
      </div>

      {/* Filters */}
      <Card>
        <h3 className="font-semibold mb-4">Filter</h3>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4">
          <Input
            type="search"
            placeholder="Search"
            value={searchTerm}
            onChange={(e) => {
              setSearchTerm(e.target.value);
              setCurrentPage(1);
            }}
          />
          <Select
            value={filterType}
            onChange={(e) => {
              setFilterType(e.target.value);
              setCurrentPage(1);
            }}
            options={[
              { value: "", label: "All Types" },
              { value: "Entrée", label: "Stock In" },
              { value: "Sortie", label: "Stock Out" },
              { value: "Transfert", label: "Transfer" },
              { value: "Retour", label: "Return" },
              { value: "Perte/Casse", label: "Loss/Damage" },
              { value: "Ajustement", label: "Adjustment" },
              { value: "Inventaire", label: "Physical Count" },
            ]}
          />
          <Select
            value={filterWarehouse}
            onChange={(e) => {
              setFilterWarehouse(e.target.value);
              setCurrentPage(1);
            }}
            options={[
              { value: "", label: "All Warehouses" },
              { value: "WH-001", label: "WH-001" },
              { value: "WH-002", label: "WH-002" },
              { value: "WH-003", label: "WH-003" },
            ]}
          />
          <Input
            type="date"
            label="From"
            value={fromDate}
            onChange={(e) => {
              setFromDate(e.target.value);
              setCurrentPage(1);
            }}
          />
          <Input
            type="date"
            label="To"
            value={toDate}
            onChange={(e) => {
              setToDate(e.target.value);
              setCurrentPage(1);
            }}
          />
        </div>
      </Card>

      {/* Movements Table */}
      <Card>
        <Table
          columns={columns}
          data={paginatedMovements}
          emptyMessage="No movements found"
        />
        <Pagination
          currentPage={currentPage}
          totalPages={Math.ceil(filteredMovements.length / itemsPerPage)}
          onPageChange={setCurrentPage}
        />
      </Card>

      {/* Add Movement Modal */}
      <Modal
        open={showAddForm}
        onClose={() => setShowAddForm(false)}
        title="Stock Movements"
        className="w-full max-w-md"
        footer={
          <>
            <Button variant="secondary" onClick={() => setShowAddForm(false)}>
              Cancel
            </Button>
            <Button onClick={() => setShowAddForm(false)}>
              Save
            </Button>
          </>
        }
      >
        <div className="space-y-4">
          <Select
            label="Type"
            options={[
              { value: "Entrée", label: "Stock In" },
              { value: "Sortie", label: "Stock Out" },
              { value: "Transfert", label: "Transfer" },
              { value: "Inventaire", label: "Physical Count" },
            ]}
            required
          />
          <Input label="Product" placeholder="Select product" required />
          <Input label="Quantity" type="number" placeholder="0" required />
          <Input label="Reason" placeholder="Movement reason" />
        </div>
      </Modal>
    </div>
  );
};
